// services/framerSync.ts
import { framer } from 'framer-plugin'

export class FramerSyncService {
  async createManagedCollection(
    name: string,
    fieldMappings: FieldMapping[]
  ) {
    const collection = await framer.getManagedCollection()

    // Convert field mappings to Framer fields
    const fields = fieldMappings.map(mapping => ({
      id: mapping.framerFieldId,
      name: mapping.notionPropertyName,
      type: mapping.framerFieldType
    }))

    await collection.setFields(fields)
    return collection
  }

  async syncItems(
    notionPages: NotionPage[],
    fieldMappings: FieldMapping[]
  ) {
    const collection = await framer.getManagedCollection()

    const items = notionPages.map(page => {
      const fieldData: Record<string, any> = {}

      fieldMappings.forEach(mapping => {
        const notionValue = page.properties[mapping.notionPropertyName]
        const parsedValue = notionService.parseNotionProperty(
          notionValue,
          mapping.notionPropertyType
        )
        fieldData[mapping.framerFieldId] = parsedValue
      })

      return {
        id: page.id,
        slug: this.generateSlug(page),
        fieldData
      }
    })

    await collection.addItems(items)
    return items.length
  }

  private generateSlug(page: NotionPage): string {
    const title = page.properties.Name?.title[0]?.plain_text || page.id
    return title.toLowerCase().replace(/\s+/g, '-')
  }
}

export const framerSyncService = new FramerSyncService()

