// App.tsx
import { useState, useEffect } from 'react'
import { framer } from 'framer-plugin'
import { AuthFlow } from './components/AuthFlow'
import { DatabaseSelector } from './components/DatabaseSelector'
import { FieldMapper } from './components/FieldMapper'
import { SyncStatus } from './components/SyncStatus'

type Step = 'auth' | 'selectDb' | 'mapFields' | 'sync'

export function App() {
  const [step, setStep] = useState<Step>('auth')
  const [config, setConfig] = useState<Partial<SyncConfig>>({})
  const [mode, setMode] = useState<string>()

  useEffect(() => {
    framer.getMode().then(setMode)
  }, [])

  const renderStep = () => {
    switch (step) {
      case 'auth':
        return <AuthFlow onComplete={(token) => {
          setConfig({ ...config, notionToken: token })
          setStep('selectDb')
        }} />
      case 'selectDb':
        return <DatabaseSelector 
          token={config.notionToken!}
          onSelect={(dbId) => {
            setConfig({ ...config, databaseId: dbId })
            setStep('mapFields')
          }}
        />
      case 'mapFields':
        return <FieldMapper
          token={config.notionToken!}
          databaseId={config.databaseId!}
          onComplete={(mappings) => {
            setConfig({ ...config, fieldMappings: mappings })
            setStep('sync')
          }}
        />
      case 'sync':
        return <SyncStatus config={config as SyncConfig} />
    }
  }

  return (
    <main className="plugin-container">
      <header>
        <h1>Notion CMS Sync</h1>
        <p>Step {['auth', 'selectDb', 'mapFields', 'sync'].indexOf(step) + 1} of 4</p>
      </header>
      {renderStep()}
    </main>
  )
}

