// services/incrementalSync.ts
export class IncrementalSyncService {
  async performIncrementalSync(
    config: SyncConfig,
    lastSyncDate: string
  ): Promise<SyncResult> {
    // Fetch only pages modified since last sync
    const pages = await notionService.queryDatabase(config.databaseId, {
      filter: {
        timestamp: 'last_edited_time',
        last_edited_time: {
          after: lastSyncDate
        }
      }
    })

    const collection = await framer.getManagedCollection()
    const existingIds = await collection.getItemIds()

    // Separate new and updated items
    const newPages = pages.filter(p => !existingIds.includes(p.id))
    const updatedPages = pages.filter(p => existingIds.includes(p.id))

    // Sync only changed items
    await framerSyncService.syncItems(
      [...newPages, ...updatedPages],
      config.fieldMappings
    )

    // Remove deleted items
    const currentIds = pages.map(p => p.id)
    const deletedIds = existingIds.filter(id => !currentIds.includes(id))
    if (deletedIds.length > 0) {
      await collection.removeItems(deletedIds)
    }

    return {
      added: newPages.length,
      updated: updatedPages.length,
      deleted: deletedIds.length
    }
  }
}

