// services/errorHandler.ts
export class SyncError extends Error {
  constructor(
    message: string,
    public code: string,
    public details?: any
  ) {
    super(message)
    this.name = 'SyncError'
  }
}

export function handleNotionError(error: any): SyncError {
  if (error.code === 'unauthorized') {
    return new SyncError(
      'Invalid Notion token. Please reconnect.',
      'AUTH_FAILED'
    )
  }
  if (error.code === 'object_not_found') {
    return new SyncError(
      'Database not found. It may have been deleted.',
      'DB_NOT_FOUND'
    )
  }
  if (error.code === 'rate_limited') {
    return new SyncError(
      'Too many requests. Please wait and try again.',
      'RATE_LIMIT',
      { retryAfter: error.headers['retry-after'] }
    )
  }
  return new SyncError(
    'An unexpected error occurred.',
    'UNKNOWN',
    error
  )
}

// Validation helpers
export function validateToken(token: string): boolean {
  return token.startsWith('secret_') && token.length > 20
}

export function validateFieldMapping(mapping: FieldMapping): string[] {
  const errors: string[] = []

  if (!mapping.framerFieldId.match(/^[a-z_][a-z0-9_]*$/)) {
    errors.push('Field ID must be lowercase with underscores')
  }

  if (mapping.framerFieldId.length > 50) {
    errors.push('Field ID must be less than 50 characters')
  }

  return errors
}

