import { framer } from 'framer-plugin'

export class AssetHandler {
  async handleNotionImage(imageUrl: string): Promise<ImageAsset> {
    try {
      // Download image from Notion
      const response = await fetch(imageUrl)
      const blob = await response.blob()
      const file = new File([blob], 'image.jpg', { type: blob.type })

      // Upload to Framer
      const asset = await framer.uploadImage({
        image: file,
        name: 'Notion Image',
        resolution: 'large'
      })

      return asset
    } catch (error) {
      console.error('Image upload failed:', error)
      throw new SyncError('Failed to upload image', 'IMAGE_UPLOAD_FAILED')
    }
  }

  async processImageField(
    notionFiles: any[],
    fieldId: string
  ): Promise<ImageAsset | null> {
    if (!notionFiles || notionFiles.length === 0) return null

    const imageUrl = notionFiles[0].file?.url || notionFiles[0].external?.url
    if (!imageUrl) return null

    return await this.handleNotionImage(imageUrl)
  }
}

