// Updated syncItems with image handling
async syncItems(
  notionPages: NotionPage[],
  fieldMappings: FieldMapping[]
) {
  const assetHandler = new AssetHandler()
  const collection = await framer.getManagedCollection()

  const items = await Promise.all(
    notionPages.map(async (page) => {
      const fieldData: Record<string, any> = {}

      for (const mapping of fieldMappings) {
        const notionValue = page.properties[mapping.notionPropertyName]

        // Special handling for images
        if (mapping.framerFieldType === 'image') {
          fieldData[mapping.framerFieldId] = await assetHandler.processImageField(
            notionValue.files,
            mapping.framerFieldId
          )
        } else {
          fieldData[mapping.framerFieldId] = notionService.parseNotionProperty(
            notionValue,
            mapping.notionPropertyType
          )
        }
      }

      return {
        id: page.id,
        slug: this.generateSlug(page),
        fieldData
      }
    })
  )

  await collection.addItems(items)
  return items.length
}

