// services/richTextParser.ts
export class RichTextParser {
  parseNotionRichText(richTextArray: any[]): string {
    return richTextArray.map(block => {
      let text = block.plain_text

      // Apply formatting
      if (block.annotations.bold) text = `**${text}**`
      if (block.annotations.italic) text = `*${text}*`
      if (block.annotations.code) text = `\`${text}\``
      if (block.annotations.strikethrough) text = `~~${text}~~`

      // Handle links
      if (block.href) text = `[${text}](${block.href})`

      return text
    }).join('')
  }

  convertToHTML(markdown: string): string {
    // Basic markdown to HTML conversion
    return markdown
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.+?)\*/g, '<em>$1</em>')
      .replace(/\`(.+?)\`/g, '<code>$1</code>')
      .replace(/~~(.+?)~~/g, '<del>$1</del>')
      .replace(/\[(.+?)\]\((.+?)\)/g, '<a href="$2">$1</a>')
  }

  async parseNotionBlocks(pageId: string): Promise<string> {
    // Fetch page blocks for full content
    const blocks = await notionService.client.blocks.children.list({
      block_id: pageId
    })

    let html = ''
    for (const block of blocks.results) {
      switch (block.type) {
        case 'paragraph':
          html += `<p>${this.parseNotionRichText(block.paragraph.rich_text)}</p>`
          break
        case 'heading_1':
          html += `<h1>${this.parseNotionRichText(block.heading_1.rich_text)}</h1>`
          break
        case 'heading_2':
          html += `<h2>${this.parseNotionRichText(block.heading_2.rich_text)}</h2>`
          break
        case 'bulleted_list_item':
          html += `<li>${this.parseNotionRichText(block.bulleted_list_item.rich_text)}</li>`
          break
      }
    }

    return html
  }
}

